374	static unsigned escape_length(const char *s, int quote)
375	{
376	    unsigned c, len = 0, step = quote == '"' ? 5 : 3;
377	    for (; (c = *s) != '\0'; ++s) {
378	        switch (c) {
379	        case '\\': case '\n': case '\r': case '\t':
380	            len += 1;
381	            break;
382	        default:
383	            if (c < 0x20)
384	                len += step;
385	            else if (c == (unsigned)quote)
386	                len += 1;
387	            break;
388	        }
389	    }
390	    return len;
391	}
