573	    if (top >= 2 && be_isstring(vm, 1) && be_isstring(vm, 2)) {
574	        /* get the operation string and its length */
575	        int len1 = be_strlen(vm, 1);
576	        int len2 = be_strlen(vm, 2);
577	        const char *s1 = be_tostring(vm, 1);
578	        const char *s2 = be_tostring(vm, 2);
579	        /* get begin and end indexes (may use default values) */
580	        bint begin = top >= 3 && be_isint(vm, 3) ? be_toint(vm, 3) : 0;
581	        bint end = top >= 4 && be_isint(vm, 4) ? be_toint(vm, 4) : len1;
582	        /* basic range check:
583	         * 1. begin position must be greater than 0 and
584	         *    less than the length of the source string.
585	         * 2. the length of the pattern string cannot be
586	         *    less than the matching range (end - begin).
587	         **/
588	        if (begin >= 0 && begin <= len1 && end - begin >= len2) {
589	            /* call the operation function */
590	            return func(s1, s2, begin, end - len2);
591	        }
592	    }
593	    return error; /* returns the default error value */
594	}
595	
596	static bint _sfind(const char *s1, const char *s2, bint begin, bint end)
597	{
598	    const char *res = strstr(s1 + begin, s2);
599	    if (res) {
600	        bint pos = (bint)(res - s1);
601	        return pos <= end ? pos : -1;
602	    }
603	    return -1;
604	}
605	
606	static int str_find(bvm *vm)
607	{
608	    be_pushint(vm, str_operation(vm, _sfind, -1));
609	    be_return(vm);
610	}
611	
612	static bint _scount(const char *s1, const char *s2, bint begin, bint end)
613	{
614	    bint count = 0;
615	    const char *res = s1 + begin, *send = s1 + end;
616	    while ((res = strstr(res, s2)) != NULL && res <= send) {
617	        count += 1;
618	        res += 1;
619	    }
620	    return count;
621	}
622	
623	static int str_count(bvm *vm)
624	{
625	    be_pushint(vm, str_operation(vm, _scount, 0));
626	    be_return(vm);
627	}
628	
629	static bbool _split_string(bvm *vm, int top)
630	{
631	    if (be_isstring(vm, 2)) {
632	        const char *res;
633	        int len1 = be_strlen(vm, 1);
634	        int len2 = be_strlen(vm, 2);
635	        const char *s1 = be_tostring(vm, 1);
636	        const char *s2 = be_tostring(vm, 2);
637	        bint count = len2 /* match when the pattern string is not empty */
638	            ? top >= 3 && be_isint(vm, 3) ? be_toint(vm, 3) : len1
639	            : 0; /* cannot match empty pattern string */
640	        while (count-- && (res = strstr(s1, s2)) != NULL) {
641	            be_pushnstring(vm, s1, res - s1);
642	            be_data_push(vm, -2);
643	            be_pop(vm, 1);
644	            s1 = res + len2;
645	        }
646	        be_pushstring(vm, s1);
647	        be_data_push(vm, -2);
648	        be_pop(vm, 1);
649	        return btrue;
650	    }
651	    return bfalse;
652	}
653	
654	static bbool _split_index(bvm *vm)
655	{
656	    if (be_isint(vm, 2)) {
657	        int len = be_strlen(vm, 1), idx = be_toindex(vm, 2);
658	        const char *s = be_tostring(vm, 1);
659	        idx = idx > len ? len : idx < -len ? -len : idx;
660	        if (idx < 0) {
661	            idx += len;
662	        }
663	        be_pushnstring(vm, s, idx);
664	        be_data_push(vm, -2);
665	        be_pop(vm, 1);
666	        be_pushnstring(vm, s + idx, (size_t)len - idx);
667	        be_data_push(vm, -2);
668	        be_pop(vm, 1);
669	        return btrue;
670	    }
671	    return bfalse;
672	}
673	
674	static int str_split(bvm *vm)
675	{
676	    int top = be_top(vm);
677	    be_newobject(vm, "list");
678	    if (top >= 2 && be_isstring(vm, 1)) {
679	        if (!_split_index(vm))
680	            _split_string(vm, top);
681	    }
682	    be_pop(vm, 1);
683	    be_return(vm);
684	}
