686	static int str_i2hex(bvm *vm)
687	{
688	    int top = be_top(vm);
689	    if (top && be_isint(vm, 1)) {
690	        bint value = be_toint(vm, 1);
691	        char fmt[10] = { "%" BE_INT_FMTLEN "X" }, buf[18];
692	        if (top >= 2 && be_isint(vm, 2)) {
693	            bint num = be_toint(vm, 2);
694	            if (num > 0 && num <= 16) {
695	                sprintf(fmt, "%%.%d" BE_INT_FMTLEN "X", (int)num);
696	            }
697	        }
698	        sprintf(buf, fmt, value);
699	        be_pushstring(vm, buf);
700	        be_return(vm);
701	    }
702	    be_return_nil(vm);
703	}
704	
705	static int str_byte(bvm *vm)
706	{
707	    if (be_top(vm) && be_isstring(vm, 1)) {
708	        const bbyte *s = (const bbyte *)be_tostring(vm, 1);
709	        be_pushint(vm, *s);
710	        be_return(vm);
711	    }
712	    be_return_nil(vm);
713	}
714	
715	static int str_char(bvm *vm)
716	{
717	    if (be_top(vm) && be_isint(vm, 1)) {
718	        char c = be_toint(vm, 1) & 0xFF;
719	        be_pushnstring(vm, &c, 1);
720	        be_return(vm);
721	    }
722	    be_return_nil(vm);
723	}
724	
725	// boolean to select whether we call toupper() or tolower()
726	static int str_touplower(bvm *vm, bbool up)
727	{
728	    if (be_top(vm) && be_isstring(vm, 1)) {
729	        const char *p, *s = be_tostring(vm, 1);
730	        size_t len = (size_t)be_strlen(vm, 1);
731	        char *buf, *q;
732	        buf = q = be_pushbuffer(vm, len);
733	        /* convert to lower case */
734	        for (p = s; *p != '\0'; ++p, ++q) {
735	            *q = up ? toupper(*p) : tolower(*p);
736	        }
737	        be_pushnstring(vm, buf, len); /* make escape string from buffer */
738	        be_remove(vm, 2); /* remove buffer */
739	        be_return(vm);
740	    }
741	    be_return_nil(vm);
742	}
743	
744	static int str_tolower(bvm *vm) {
745	    return str_touplower(vm, bfalse);
746	}
747	
748	static int str_toupper(bvm *vm) {
749	    return str_touplower(vm, btrue);
750	}
